def load_data_from_path(file_path):
    df =  pd.read_csv(file_path)
    df.columns = ['Header1', 'company','label','text']
    df.dropna(inplace=True)
    df.drop_duplicates(inplace=True)
    df.drop(columns=['Header1', 'company'], inplace=True)
    return df
