def text_encode1(text, maxlen = 166, ):
    text = clean_text(text)
    encoded_sentence = vocab(tokenizer(text))
    if len(encoded_sentence) < maxlen:
        encoded_sentence = encoded_sentence + [0] * (maxlen - len(encoded_sentence))
